import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI, Type } from "@google/genai";
import dotenv from "dotenv";

dotenv.config();

async function startServer() {
  const app = express();
  app.use(express.json());
  const PORT = 3000;

  let aiClient: GoogleGenAI | null = null;
  function getGenAI() {
    if (!aiClient) {
      const key = process.env.GEMINI_API_KEY;
      if (!key || key === "MY_GEMINI_API_KEY" || key.trim() === "") {
        return null;
      }
      aiClient = new GoogleGenAI({
        apiKey: key,
        httpOptions: {
          headers: {
            'User-Agent': 'aistudio-build',
          }
        }
      });
    }
    return aiClient;
  }

  // API Route for dynamic case generation
  app.post("/api/cases/generate", async (req: express.Request, res: express.Response) => {
    const { difficulty, selectedType } = req.body;
    const ai = getGenAI();

    if (!ai) {
      return res.json({
        success: false,
        isOffline: true,
        message: "Offline local case mode enabled: GEMINI_API_KEY is not defined in Secrets."
      });
    }

    try {
      const requestedDifficulty = difficulty || 'officer';
      const typeFilter = selectedType ? `of specifically the category "${selectedType}"` : "of any arbitrary common grammatical violation category";

      const prompt = `Generate a high-quality, entertaining single-sentence grammar crime case card for a "Grammar Police Detective" gameplay.
The sentence can refer to detective themes or daily things, but must contain EXACTLY ONE subtle, deliberate grammatical mistake ${typeFilter} suitable for a level "${requestedDifficulty}" investigator.

Required Schema Constraints:
1. The error must be isolated inside exactly one word.
2. The split of the sentence by a single space must result in a words array where the word at the specified errorWordIndex is the exact wrong word.
3. Be highly amusing, thematic, relating to police work, interrogations, sneaky criminals, or funny citizens on patrol.
4. The errorType must be a machine-readable string matching one of: homophone, subject_verb, dangling_modifier, apostrophe, tense_shift, redundancy, who_whom, affect_effect.
5. The errorLabel should be an authoritative description of the crime class (e.g. "Dangling Modifier Menace", "The Homophone Hijacking").
6. Provide a premium, educational, police-report-style explanation of why this violates grammatical law.
7. Assign a funny perpetrator name ('suspectName') (e.g., "Slippery Syntax Sam", "The Redundant Ranger").
8. Ensure difficulty matches exactly "${requestedDifficulty}".`;

      const response = await ai.models.generateContent({
        model: "gemini-3.5-flash",
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              sentence: { type: Type.STRING, description: "The full sentence containing the error." },
              errorWordIndex: { type: Type.INTEGER, description: "The zero-based index of the erroneous word when splitting the sentence by single space ' '." },
              errorType: { type: Type.STRING, description: "One of: homophone, subject_verb, dangling_modifier, apostrophe, tense_shift, redundancy, who_whom, affect_effect" },
              errorLabel: { type: Type.STRING, description: "Human-friendly label of the crime." },
              correction: { type: Type.STRING, description: "The correct spelling, conjugation, or replacement word/phrase for that specific index." },
              correctedSentence: { type: Type.STRING, description: "The complete corrected sentence." },
              explanation: { type: Type.STRING, description: "Police report commentary explaining the grammatical law violated." },
              difficulty: { type: Type.STRING, description: "Strictly one of: 'cadet', 'officer', 'sergeant', 'detective'." },
              suspectName: { type: Type.STRING, description: "Entertaining fictional suspect name." }
            },
            required: ["sentence", "errorWordIndex", "errorType", "errorLabel", "correction", "correctedSentence", "explanation", "difficulty", "suspectName"]
          }
        }
      });

      const responseText = response.text;
      if (!responseText) {
        throw new Error("Empty response returned from the Gemini engine.");
      }

      const caseData = JSON.parse(responseText.trim());
      const words = caseData.sentence.trim().split(' ');
      
      // Sanitization check on generated index
      let finalIndex = parseInt(caseData.errorWordIndex);
      if (isNaN(finalIndex) || finalIndex < 0 || finalIndex >= words.length) {
        // Safe scan fallback just in case
        finalIndex = words.findIndex((w: string) => 
          w.toLowerCase().includes(caseData.correction.toLowerCase()) || 
          caseData.sentence.toLowerCase().includes(w.toLowerCase())
        );
        if (finalIndex === -1) {
          finalIndex = 0;
        }
      }

      res.json({
        success: true,
        case: {
          id: `ai_${Date.now()}`,
          sentence: caseData.sentence,
          words,
          errorWordIndex: finalIndex,
          errorType: caseData.errorType,
          errorLabel: caseData.errorLabel,
          correction: caseData.correction,
          correctedSentence: caseData.correctedSentence,
          explanation: caseData.explanation,
          difficulty: caseData.difficulty,
          suspectName: caseData.suspectName,
          isAI: true
        }
      });

    } catch (err: any) {
      console.error("Gemini query failure in API:", err);
      res.json({
        success: false,
        error: err.message || "Failed to call Gemini AI generator.",
        message: "Fell back to local databases."
      });
    }
  });

  // Enable static production serving or dev routing
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req: express.Request, res: express.Response) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server executing at http://0.0.0.0:${PORT}`);
  });
}

startServer();
